let ssrSymbolIds = null;

/**
 * Returns the IDs of all symbols available for reference
 * @returns {array} An array of the IDs of the symbols that are present in the
 * symbol drop
 */
export function getSSRSymbolIDs(symbolsClass) {
  if (!document) {
    return null;
  }

  ssrSymbolIds = Array.from(
    document.querySelectorAll(`.${symbolsClass} symbol`),
    ({ id }) => id,
  );

  return ssrSymbolIds;
}

/**
 * Returns true/false depending on whether the icon has already been rendered
 * into a symbol drop
 * @param {string} id id of the symbol
 * @param {string} symbolsClass selector for the symbols drop
 * @returns {bool} Whether or not a symbol exists matching the given ID
 */
export function existsAsSymbol(id, symbolsClass) {
  const ids = ssrSymbolIds || getSSRSymbolIDs(symbolsClass);
  const existsAsSymbol = Array.isArray(ids) && ids.includes(id);

  return existsAsSymbol;
}

/**
 * Called following any updateTakes in an array of the properties to all of the
 * mounted instances of the icon component
 * @param {array} newState an array of the properties to all of the mounted
 * instances of Icons
 * @returns {array} A unique permutation of the array of Icon components as
 * generated by Icons
 */
export function reducePropsToState(newState) {
  const reducedState = [
    ...new Map(newState.map((item) => [item.id, item])).values(),
  ];

  return reducedState;
}

/**
 * Invoked during CSR with the return value of reducePropsToState, it is used to
 * then emit a side effect
 *
 * @param {array} reducedState A unique permutation of the array of Icon
 * components as generated by Icons
 * @returns {array}
 */
export function handleStateChangeOnClient(reducedState = []) {
  /**
   * It is not possible to render the icons on the client without setting up
   * another Symbol drop for each rehydratable component or rehydrating an
   * existing Symbol drop and sharing the same instance of SideEffect. This is
   * because Chrome is currently unable to render the SVGs dynamically added to
   * the shadow DOM. It's simpler, therefore, to just render-inline any CSR
   * icons that have not been added to a Symbol drop as part of the SSR.
   * @see https://bugs.chromium.org/p/chromium/issues/detail?id=1099181
   */

  return reducedState;
}

/**
 * Invoked during SSR, this is equivalent to handleStateChangeOnClient and
 * offers an opportunity to augment the icon stack before it is committed to
 * state
 * @param {array} reducedState A unique permutation of the array of Icon
 * components as generated by Icons
 * @returns {array}
 */
export function mapStateOnServer(reducedState = []) {
  return reducedState;
}
