import PropTypes from 'prop-types';
import withSideEffect from 'react-side-effect';

import { CLASS_SYMBOLS_DROP } from './Icon.constants';
import {
  reducePropsToState,
  handleStateChangeOnClient,
  mapStateOnServer,
  existsAsSymbol,
} from './Icon.helpers';
import { symbolsPropTypes } from './Icon.types';
import { SVG, Symbol } from './SVG';

const SideEffects = withSideEffect(
  reducePropsToState,
  handleStateChangeOnClient,
  mapStateOnServer,
)(SVG);

const withIconSideEffect = (Icon) => {
  const Wrapped = ({ svg, ...rest }) => {
    const {
      props: { children, id, viewBox, ...attrs },
    } = svg();

    // Render an inline SVG if the symbol doesn't already exist in a Symbol drop
    const isInline =
      SideEffects.canUseDOM && !existsAsSymbol(id, CLASS_SYMBOLS_DROP);

    return (
      <Icon {...attrs} {...rest} id={id} isInline={isInline} viewBox={viewBox}>
        {children}
      </Icon>
    );
  };

  Wrapped.propTypes = {
    svg: PropTypes.func.isRequired,
  };

  return Wrapped;
};

/**
 * Adds a reference to a symbol that will be dropped onto the page or
 */
export const Icon = withIconSideEffect(SideEffects);

/**
 * Component for 'dropping' the symbols on the page. This component currently
 * only really applies during SSR. @see handleStateChangeOnClient
 * @returns An SVG element containing a unique permutation of <use /> elements
 * containing the icons that have been declared using the Icon component
 */
export const Symbols = () => {
  const method = SideEffects.canUseDOM ? 'peek' : 'rewind';
  const mappedState = (SideEffects[method] && SideEffects[method]()) || [];

  return (
    mappedState?.length > 0 && (
      <svg
        className={CLASS_SYMBOLS_DROP}
        xmlns="http://www.w3.org/2000/svg"
        hidden={true}
      >
        {mappedState.map(({ children, id, viewBox }) => (
          <Symbol key={id} id={id} viewBox={viewBox}>
            {children}
          </Symbol>
        ))}
      </svg>
    )
  );
};

Symbols.propTypes = symbolsPropTypes;
