import { styled } from 'styled-components';

import { SIZE_BASE as ICON_SIZE_BASE } from './Icon.constants';
import {
  svgPropTypes,
  inlinePropTypes,
  usePropTypes,
  symbolPropTypes,
} from './Icon.types';

const Wrapper = styled.svg`
  --width: ${({ theme, $size }) => theme.dimension.icon[$size].width}px;
  display: block;
  width: var(--width);
  height: var(--width);
  color: currentColor;
`;

export const Inline = ({
  children,
  className,
  viewBox,
  size = ICON_SIZE_BASE,
  ...rest
}) => {
  /**
   * @todo refactor this so that we only ever pass in relevant props in the
   * first place
   */
  const attrs = Object.fromEntries(
    Object.entries(rest).filter(
      ([attr]) => !['Symbol', 'svg', 'name'].includes(attr),
    ),
  );

  return (
    <Wrapper className={className} viewBox={viewBox} $size={size} {...attrs}>
      {children}
    </Wrapper>
  );
};

Inline.propTypes = inlinePropTypes;

export const Use = ({ className, id, size = ICON_SIZE_BASE }) => {
  return (
    <Wrapper $size={size} className={className}>
      <use href={`#${id}`} />
    </Wrapper>
  );
};

Use.propTypes = usePropTypes;

export const SVG = ({ isInline = true, children, ...rest }) => {
  if (isInline) {
    return <Inline {...rest}>{children}</Inline>;
  }

  return <Use {...rest} />;
};

SVG.propTypes = svgPropTypes;

export const Symbol = ({ children, id, viewBox }) => (
  <symbol id={id} viewBox={viewBox}>
    {children}
  </symbol>
);

Symbol.propTypes = symbolPropTypes;
