import PropTypes from 'prop-types';

import {
  SIZE_SMALL,
  SIZE_BASE,
  SIZE_LARGE,
  SIZE_XX_LARGE,
} from './Icon.constants';

export const symbolsPropTypes = {};

export const svgPropTypes = {
  className: PropTypes.string,
  children: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.arrayOf(PropTypes.node),
  ]),
  id: PropTypes.string.isRequired,
  isInline: PropTypes.bool,
  size: PropTypes.oneOf([SIZE_SMALL, SIZE_BASE, SIZE_LARGE, SIZE_XX_LARGE]),
  viewBox: PropTypes.string,
};

export const inlinePropTypes = {
  ...svgPropTypes,
  children: svgPropTypes.children.isRequired,
  viewBox: svgPropTypes.viewBox.isRequired,
};

export const usePropTypes = {
  ...svgPropTypes,
};

export const symbolPropTypes = {
  children: svgPropTypes.children.isRequired,
  viewBox: svgPropTypes.viewBox.isRequired,
};
